// Button Group (no topic) → DIMMER_COMMAND_2 (0x1FEDB) with configurable timer
// Expected button values: "on" | "off" | "timer"
// Sends frame [INSTANCE, 0x00, LEVEL] to socketcan-out
// Node status shows: ON, OFF, and TIMER started

const DGN        = 0x1FEDB;   // DIMMER_COMMAND_2 (g12)
const INSTANCE   = 44;        // set instance to g12 output
const DEST_ADDR  = 0x01;      // destination SA
const ON_LEVEL   = 251;
const OFF_LEVEL  = 0;
const TIMER_MIN  = 15;        // Timer length (minutes)

// ---- helpers ----
function buildFrame(dgn, da, data) {
  return {
    canid: (dgn << 8) | (da & 0xFF),
    ext: true,
    rtr: false,
    dlc: data.length,
    data
  };
}

function sendLevel(level) {
  const frame = buildFrame(DGN, DEST_ADDR, [INSTANCE, 0x00, level & 0xFF]);
  node.send({ payload: frame });
  node.status({
    fill: level > 0 ? "green" : "grey",
    shape: "dot",
    text: level > 0 ? "ON (251)" : "OFF (0)"
  });
}

const turnOn  = () => sendLevel(ON_LEVEL);
const turnOff = () => sendLevel(OFF_LEVEL);

// ---- timer management (auto-OFF after TIMER_MIN) ----
function cancelTimer() {
  const t = context.get("activeTimer");
  if (t) clearTimeout(t);
  context.set("activeTimer", null);
  context.set("timerEndsAt", null);
}

