  cancelTimer();
  const ms = Math.max(1, minutes) * 60 * 1000;
  const endsAt = Date.now() + ms;
  context.set("timerEndsAt", endsAt);

  // Status: TIMER started
  node.status({
    fill: "blue",
    shape: "ring",
    text: `TIMER started (${minutes}m)`
  });

  const t = setTimeout(() => {
    // When timer ends -> OFF (status will show OFF from sendLevel)
    turnOff();
    cancelTimer();
    // Optional: add a brief 'Timer ended' note (comment out if not desired)
    // node.status({ fill: "grey", shape: "ring", text: "Timer ended → OFF" });
  }, ms);

  context.set("activeTimer", t);
}

