// Function node with 2 outputs:
//  - Output 1: socketcan-out (DIMMER_COMMAND_2: 0x1FEDB)
//  - Output 2: dashboard-2 switch group (True/False options)
// Behavior:
//   input true  -> pulse Instance 3 for 1s, select TRUE option in the group
//   input false -> pulse Instance 4 for 1s, select FALSE option in the group
// After pulse finishes, the switch group is "blanked" (no selection).

// ---------- CONFIG ----------
const DGN        = 0x1FEDB;
const DEST_ADDR  = 0x01;   // adjust target SA if needed
const GROUP      = 0x00;
const TRUE_INST  = 3;
const FALSE_INST = 4;
const ON_LEVEL   = 200;    // 251 if you want full on
const OFF_LEVEL  = 0;
const PULSE_MS   = 1000;   // 1 second

// Dashboard 2 switch-group value tokens (MUST match your widget's option values)
const TRUE_OPTION_VALUE  = "true";   // e.g. "true" or true
const FALSE_OPTION_VALUE = "false";  // e.g. "false" or false

// Switch-group message shape: most D2 widgets accept {value: ...}
const SWITCH_MSG_SHAPE = "value"; // "value" → send {value: ...}; "payload" → send raw

const SWITCH_TOPIC = "pulseSwitchGroup"; // optional: set the same topic on your D2 widget
const BLANK_DELAY_MS = 80;  // delay before sending blank after OFF
// ---------------------------------------

function buildFrame(dgn, da, data) {
  return { canid: (dgn << 8) | (da & 0xFF), ext: true, rtr: false, dlc: data.length, data };
}

// Normalize incoming value to strict boolean
function toBool(input) {
  let v = input;
  if (v && typeof v === "object" && "value" in v) v = v.value;
  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (s === "true" || s === "on"  || s === "1") return true;
    if (s === "false"|| s === "off" || s === "0") return false;
  }
  if (v === true || v === 1) return true;
  if (v === false || v === 0) return false;
  return null; // unknown
}

function sendGroup(valueToken) {
  if (SWITCH_MSG_SHAPE === "value") {
    node.send([ null, { topic: SWITCH_TOPIC, payload: { value: valueToken } } ]);
  } else {
    node.send([ null, { topic: SWITCH_TOPIC, payload: valueToken } ]);
  }
}

function blankGroup() {
  if (SWITCH_MSG_SHAPE === "value") {
    node.send([ null, { topic: SWITCH_TOPIC, payload: { value: null } } ]);
  } else {
    node.send([ null, { topic: SWITCH_TOPIC, payload: null } ]);
  }
}

const b = toBool(msg.payload);
if (b === null) return null;  // ignore unknown inputs

// Choose instance + switch-group token
const inst = b ? TRUE_INST : FALSE_INST;
const token = b ? TRUE_OPTION_VALUE : FALSE_OPTION_VALUE;

// Cancel any pending timers for this instance
const keyOff   = "timer_off_"   + inst;
const keyBlank = "timer_blank_" + inst;
const tOff   = context.get(keyOff);
const tBlank = context.get(keyBlank);
if (tOff)   clearTimeout(tOff);
if (tBlank) clearTimeout(tBlank);

// --- Send ON on CAN + set group to selected option ---
node.send([ { payload: buildFrame(DGN, DEST_ADDR, [inst, GROUP, ON_LEVEL]) }, null ]);
sendGroup(token);

// --- Schedule OFF and then blank the group ---
const offTimer = setTimeout(() => {
  node.send([ { payload: buildFrame(DGN, DEST_ADDR, [inst, GROUP, OFF_LEVEL]) }, null ]);

  const blankTimer = setTimeout(() => {
    blankGroup();                 // clears selection in the switch group
    context.set(keyBlank, null);
  }, BLANK_DELAY_MS);

  context.set(keyBlank, blankTimer);
  context.set(keyOff, null);
}, PULSE_MS);

context.set(keyOff, offTimer);

return null;

