// Inject (timestamp) -> this function -> socketcan-out
// Sends RV-C SET_DATE_TIME_COMMAND with *current local system time*.

// RV-C command
const DGN       = 0x1FFFE; // SET_DATE_TIME_COMMAND
const DEST_ADDR = 0xFF;    // broadcast (change to a specific SA if needed)

// Build a 29-bit extended CAN frame
function buildFrame(dgn, da, data) {
  return {
    canid: (dgn << 8) | (da & 0xFF),
    ext: true,
    rtr: false,
    dlc: data.length,
    data
  };
}

// RV-C DOW: 1=Sunday..7=Saturday (JS: 0..6 with 0=Sun)
const rvcDow = (jsDow) => (jsDow === 0 ? 1 : jsDow + 1);

// Example TZ code mapping for US Pacific: 7=PDT, 8=PST.
// Adjust this function for your locale if your receivers expect a specific enum.
function pacificTzCode(date) {
  const y = date.getFullYear();
  const jan = new Date(y, 0, 1).getTimezoneOffset();
  const jul = new Date(y, 6, 1).getTimezoneOffset();
  const std = Math.max(jan, jul);
  const isDst = date.getTimezoneOffset() < std;
  return isDst ? 7 : 8;
}

// --- Use the current local system time ---
const dt = new Date(); // local time

const yearByte   = Math.max(0, Math.min(255, dt.getFullYear() - 2000)); // 2000..2255
const monthByte  = dt.getMonth() + 1;      // 1..12
const dayByte    = dt.getDate();           // 1..31
const dowByte    = rvcDow(dt.getDay());    // 1..7
const hourByte   = dt.getHours();          // 0..23 (local)
const minuteByte = dt.getMinutes();        // 0..59
const secondByte = dt.getSeconds();        // 0..59
const tzByte     = pacificTzCode(dt);      // change if your network expects a different code

const frame = buildFrame(DGN, DEST_ADDR, [
  yearByte, monthByte, dayByte, dowByte,
  hourByte, minuteByte, secondByte, tzByte
]);

