  shape: "dot",
  text: `Sent ${monthByte}/${dayByte}/${2000+yearByte} ${hourByte.toString().padStart(2,"0")}:${minuteByte.toString().padStart(2,"0")}:${secondByte.toString().padStart(2,"0")} tz=${tzByte}`
});

return { payload: frame };

